document.addEventListener("DOMContentLoaded",(function(){const e=document.querySelector(".repair-form");e&&e.addEventListener("submit",(async function(t){t.preventDefault();const n={name:document.getElementById("full-name").value,email:document.getElementById("email-address").value,phone:document.getElementById("phone-no").value,serviceType:document.getElementById("service-type").value,deviceType:document.getElementById("device-type").value,issueDescription:document.getElementById("request").value},a=document.createElement("div");a.className="form-message",e.prepend(a);try{const t=await fetch("/api/forms/repair-upgrade",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)}),r=await t.json();t.ok?(a.innerHTML=`<div class="alert alert-success">${r.message}</div>`,e.reset()):a.innerHTML=`<div class="alert alert-danger">${r.message}</div>`}catch(e){a.innerHTML='<div class="alert alert-danger">An error occurred. Please try again.</div>'}}))}));